int db_note_get_by_id(int note_id, Note* note) {
    if (g_db == NULL) return -1;

    sqlite3_stmt* stmt;
    int rc = sqlite3_prepare_v2(g_db, SELECT_NOTE_BY_ID, -1, &stmt, NULL);
    if (rc != SQLITE_OK) return -1;

    sqlite3_bind_int(stmt, 1, note_id);

    if (sqlite3_step(stmt) == SQLITE_ROW) {
        note->id = sqlite3_column_int(stmt, 0);
        note->user_id = sqlite3_column_int(stmt, 1);
        strncpy(note->title, (const char*)sqlite3_column_text(stmt, 2), MAX_NOTE_TITLE_LEN - 1);

        if (sqlite3_column_text(stmt, 3)) {
            strncpy(note->content, (const char*)sqlite3_column_text(stmt, 3), MAX_NOTE_CONTENT_LEN - 1);
        } else {
            note->content[0] = '\0';
        }

        note->is_deleted = sqlite3_column_int(stmt, 4);

        if (sqlite3_column_text(stmt, 5)) {
            strncpy(note->created_at, (const char*)sqlite3_column_text(stmt, 5), 31);
        } else {
            note->created_at[0] = '\0';
        }

        if (sqlite3_column_text(stmt, 6)) {
            strncpy(note->updated_at, (const char*)sqlite3_column_text(stmt, 6), 31);
        } else {
            note->updated_at[0] = '\0';
        }

static const char* get_param(struct mg_connection* conn, const char* name, char* buf, size_t buf_size) {
    const struct mg_request_info* ri = mg_get_request_info(conn);

    // 先尝试从 query_string 获取 (GET 请求)
    if (ri->query_string) {
        int len = mg_get_var(ri->query_string, strlen(ri->query_string), name, buf, buf_size);
        if (len > 0) return buf;
    }

    // 尝试从 POST 数据获取
    // 读取 POST 数据
    char post_data[MAX_POST_DATA];
    int post_len = mg_read(conn, post_data, sizeof(post_data) - 1);
    if (post_len > 0) {
        post_data[post_len] = '\0';
        int len = mg_get_var(post_data, post_len, name, buf, buf_size);
        if (len > 0) return buf;
    }

    return NULL;
}

